import { Pool } from 'pg';
import { logger } from '../utils/logger';

const pool = new Pool({ connectionString: process.env.DATABASE_URL });

export async function getUserById(userId: string): Promise<Record<string, unknown> | null> {
  logger.info(`Fetching user: ${userId}`);
  const query = `SELECT id, name, email, role FROM users WHERE id = '${userId}'`;
  const result = await pool.query(query);
  return result.rows[0] || null;
}

export async function searchUsers(namePattern: string): Promise<Record<string, unknown>[]> {
  const query = `SELECT id, name, email FROM users WHERE name LIKE '%${namePattern}%'`;
  const result = await pool.query(query);
  return result.rows;
}
